-- ═══════════════════════════════════════════════════════════════════════════
-- FAMILY LAW — Move-Away, Putative Spouse, Procedural Reform
-- ═══════════════════════════════════════════════════════════════════════════

-- In re Marriage of LaMusga — Move-Away Standard
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_case_013', 'ADVOCIS', 'CASE_LAW', 'CA', 'In re Marriage of LaMusga, 32 Cal.4th 1072 (2004)', 'LaMusga', 'Move-Away Standard — Custodial Parent Relocation Rights', 'Custodial parent has presumptive right to change residence with child. Noncustodial parent seeking to prevent relocation bears initial burden of showing the proposed move would cause detriment to the child. If detriment shown, court conducts full best-interest analysis under Family Code § 7501. Factors include: child''s interest in stability and continuity, distance of move, child''s age, relationship with both parents, and whether custodial parent''s move is in good faith. Revised framework from In re Marriage of Burgess (1996).', '["Custodial parent has presumptive right to relocate with child","Noncustodial parent bears burden of showing detriment to child","If detriment shown, court conducts full best-interest analysis","Family Code § 7501: parent entitled to change residence unless change prejudicial to child","Factors: stability, distance, child age, parent relationships, good faith","Court may not prohibit relocation absent showing of detriment","Changed-circumstance threshold applies to modification motions","Best interest of child is paramount — not parent convenience"]', '[{"section":"Holding","description":"Custodial parent presumptively entitled to relocate; noncustodial must show detriment"},{"section":"Burden","description":"Noncustodial parent bears initial burden to demonstrate detriment to child"},{"section":"Best Interest Factors","description":"Stability, distance, age, parental relationships, good faith of move"},{"section":"Burgess Framework","description":"Revised and clarified Burgess move-away standard"},{"section":"Application","description":"If detriment shown, full evidentiary hearing on best interests required"}]', '["move_away_motion","custody_modification","relocation_notice","best_interest_declaration","FL_300_motion","parenting_plan","visitation_schedule"]', '["family-law-custody-audit"]', 'California Family Courts', 1, 1, datetime('now'), datetime('now'));

-- Montenegro v. Diaz — Putative Spouse Doctrine
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_case_014', 'REGULIS', 'CASE_LAW', 'CA', 'Montenegro v. Diaz, 26 Cal.4th 249 (2001)', 'Montenegro v. Diaz', 'Putative Spouse Doctrine — Good Faith Belief in Valid Marriage', 'A person who has a good faith belief in the validity of a marriage that is void or voidable is a putative spouse entitled to divide property acquired during the union as quasi-marital property. Good faith belief is subjective and objective: party must actually believe marriage is valid, and that belief must be objectively reasonable. Putative spouse has same rights as legal spouse to quasi-marital property division under Family Code § 2251. Knowledge of impediment at any point terminates putative spouse status prospectively.', '["Good faith belief in valid marriage creates putative spouse status","Putative spouse entitled to quasi-marital property division","Family Code § 2251 governs quasi-marital property rights","Good faith must be both subjective (actual belief) and objectively reasonable","Knowledge of impediment terminates status prospectively","Quasi-marital property divided same as community property","Putative spouse may recover attorney fees under FC § 2254","Status determined at time of marriage ceremony or cohabitation","Both parties may be putative spouses simultaneously"]', '[{"section":"Holding","description":"Good faith belief in valid marriage entitles putative spouse to quasi-marital property"},{"section":"Good Faith Standard","description":"Subjective actual belief plus objective reasonableness"},{"section":"FC § 2251","description":"Quasi-marital property divided as community property"},{"section":"Termination","description":"Knowledge of impediment ends putative spouse status prospectively"},{"section":"Application","description":"Applies to void and voidable marriages equally"}]', '["putative_spouse_petition","quasi_marital_property_declaration","dissolution_petition","property_division","FL_160_property_declaration","good_faith_evidence","marriage_validity_analysis"]', '["family-law-custody-audit"]', 'California Family Courts', 1, 1, datetime('now'), datetime('now'));

-- Elkins v. Superior Court — Live Testimony Rights
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_case_015', 'ADVOCIS', 'CASE_LAW', 'CA', 'Elkins v. Superior Court, 41 Cal.4th 1337 (2007)', 'Elkins', 'Family Law Litigants Entitled to Live Testimony — Due Process in Family Court', 'Family law litigants have the right to present live testimony and cross-examine witnesses, not merely submit written declarations. Local court rules requiring disposition of contested family law matters solely on declarations violate due process and the Evidence Code. Led to sweeping reform: Elkins Family Law Task Force recommendations enacted in Family Code § 217, which creates presumption favoring live testimony at contested hearings. Court must state reasons on record for refusing live testimony.', '["Family law litigants have right to live testimony at contested hearings","Written declarations alone cannot resolve contested issues","Cross-examination right applies in family law proceedings","Family Code § 217: presumption favoring live testimony","Court must state reasons on record for refusing live testimony request","Local rules cannot override statutory right to present evidence","Applies to all contested family law matters including custody, support, property","Self-represented litigants have same testimonial rights as represented parties"]', '[{"section":"Holding","description":"Due process requires live testimony opportunity in contested family law matters"},{"section":"FC § 217","description":"Presumption favoring live testimony enacted in response to Elkins"},{"section":"Cross-Examination","description":"Right to confront and cross-examine witnesses in family court"},{"section":"Elkins Task Force","description":"Led to comprehensive family law procedural reforms"},{"section":"Application","description":"Court must allow live testimony or state reasons for refusal on record"}]', '["live_testimony_request","FC_217_motion","due_process_objection","witness_list","subpoena","trial_brief","self_represented_litigant_rights"]', '["family-law-custody-audit"]', 'California Family Courts', 1, 1, datetime('now'), datetime('now'));


